INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3190d2c9-97ab-4131-81ee-15a9bb5745a2', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Double-entry bookkeeping$q$, $q$Every transaction moves money from one account to another rather than logging an isolated debit or credit, giving more rigorous and auditable financial records than typical budgeting apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Budgets, categories, and tags$q$, $q$Users set monthly budget amounts and organize every transaction with categories and free-form tags for granular reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Rules engine$q$, $q$Custom rules automatically categorize, tag, or assign transactions to budgets based on conditions like description, amount, or account, reducing manual upkeep.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Recurring transactions$q$, $q$Bills and subscriptions can be modeled as recurring transactions that generate entries on a defined schedule.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Piggy banks$q$, $q$Savings goals tied to specific accounts let users track progress toward a target amount over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Multi-currency support$q$, $q$Firefly III supports any currency and allows multiple currencies to be used simultaneously across different accounts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$REST JSON API$q$, $q$Nearly every feature of the application is exposed through a documented REST API, enabling custom scripts, dashboards, and the official Data Importer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Automated bank import via Firefly III Data Importer$q$, $q$A companion application imports transactions from CSV files or automatically from thousands of PSD2-compliant banks via Nordigen/GoCardless and SaltEdge.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Completely free with no paid tiers, premium feature gates, or usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Self-hosted architecture keeps financial data under the user's own control and off third-party servers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Genuine double-entry bookkeeping and a scriptable rules engine offer more rigor than typical consumer budgeting apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Full REST API enables custom integrations, automation, and third-party client apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Actively maintained with over a decade of history, regular releases, and a large public GitHub community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Requires self-hosting knowledge (Docker, a web server, and a database), which is a barrier for non-technical users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$No official first-party mobile app; mobile access depends on community-built clients like Abacus or Waterfly III$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Automated bank sync via the Data Importer depends on third-party services (Nordigen/GoCardless, SaltEdge) that require separate registration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$The user is responsible for their own backups, uptime, and server security since there is no managed hosting option$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Is Firefly III really free?$q$, $q$Yes. Firefly III is free and open-source software (AGPL-3.0) with no paid tiers, premium features, or usage limits. The developer accepts optional donations via Patreon, GitHub Sponsors, Ko-fi, and Liberapay, but the software is fully functional without paying anything.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Do I need my own server to use Firefly III?$q$, $q$Yes. Firefly III is self-hosted, so you need to run it yourself, typically via the official Docker image, on a VPS, home server, NAS, or Kubernetes cluster. There is no first-party hosted cloud version offered by the project.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$What database and server requirements does Firefly III have?$q$, $q$The current release line requires PHP 8.4 and supports MySQL, PostgreSQL, or SQLite as the database. It can run on a standard LAMP or LEMP stack, WAMP on Windows, via Docker, or via Kubernetes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$How do I import transactions from my bank?$q$, $q$You can upload CSV files manually, or use the companion Firefly III Data Importer, which connects to Nordigen/GoCardless and SaltEdge to automatically pull transactions from thousands of PSD2-compliant banks across the EU and UK after free registration with those providers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Is there an official Firefly III mobile app?$q$, $q$No, there is no official first-party mobile app. The project's API is used by community-built clients such as Abacus (iOS and Android) and Waterfly III and Photuris III (Android).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$How is Firefly III different from GnuCash, YNAB, or Actual Budget?$q$, $q$Firefly III combines a true double-entry ledger, a scriptable rules engine, and a full REST API in a self-hosted package. GnuCash is an older desktop accounting app without native web or API access; YNAB is a paid cloud subscription with no self-hosting option; Actual Budget is an open-source, MIT-licensed alternative focused on zero-based envelope budgeting rather than double-entry bookkeeping.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Privacy-focused personal budgeting$q$, $q$Individuals who do not want their bank transaction history uploaded to a commercial fintech company can track spending, income, and savings entirely on infrastructure they control.$q$, $q$Privacy-conscious individuals and households$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Home server and homelab finance tracking$q$, $q$Users already running a Docker or Kubernetes homelab, or a NAS with an app store like Umbrel, can add Firefly III alongside other self-hosted services and manage finances the same way they manage the rest of their infrastructure.$q$, $q$Self-hosters and homelab operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Detailed bookkeeping for freelancers and small budgets$q$, $q$Users who want real double-entry bookkeeping, rule-based auto-categorization, and API access for custom reporting, without paying for commercial accounting software, can use Firefly III to keep structured, auditable records.$q$, $q$Freelancers, developers, and detail-oriented budgeters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to all features with no usage limits","Double-entry bookkeeping, budgets, categories, tags, and rules engine","REST JSON API","Firefly III Data Importer for CSV and bank sync via Nordigen/GoCardless and SaltEdge","Requires self-hosting (Docker, LAMP/LEMP, or Kubernetes) and a MySQL, PostgreSQL, or SQLite database"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Firefly III is a free, open-source personal finance manager that you install and run on your own server instead of using as a hosted cloud product. Built by developer James Cole (JC5) in PHP on the Laravel framework, it implements a genuine double-entry bookkeeping system, meaning every transaction is recorded as money moving between two accounts, which gives it more rigor than typical consumer budgeting apps.$q$, $q$The project is released under the GNU Affero General Public License v3 (AGPL-3.0), with its source code hosted publicly on GitHub (and mirrored on Codeberg). It is aimed at technically comfortable users, including self-hosters, homelab operators, and privacy-conscious individuals who want to keep their financial data off third-party servers entirely.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Firefly III lets users create monthly budgets, organize transactions with categories and tags, and set up recurring transactions for bills and subscriptions. A rules engine automatically categorizes, tags, or routes incoming transactions based on user-defined conditions, reducing manual bookkeeping work over time.$q$, $q$Additional capabilities include piggy banks for tracking progress toward savings goals, support for any currency (including multiple currencies across different accounts at once), two-factor authentication, detailed income and expense reports with charts, and a comprehensive REST JSON API that exposes nearly every part of the application for custom integrations, scripts, and the official data importer.$q$, $q$Transaction data can be brought in manually via CSV or automatically through the companion Firefly III Data Importer, which connects to Nordigen/GoCardless and SaltEdge to pull transactions from thousands of PSD2-compliant banks across the EU and UK, subject to free registration with those providers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Firefly III is entirely free to self-host, with no paid tiers, no premium feature gate, and no usage limits on transactions, accounts, budgets, or API calls. Because it is self-hosted, the only real cost is whatever server or hosting infrastructure (a small VPS, a Docker host, a home NAS, and so on) you choose to run it on.$q$, $q$The project itself is sustained through voluntary donations to James Cole via Patreon, GitHub Sponsors, Ko-fi, and Liberapay. Per the project's own documentation, this funding covers costs like hosting the public demo instance and gives the developer more time to work on Firefly III, but it does not unlock any additional features for sponsors.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f92f756-1ddd-475c-a7ab-6671d8405485', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Node.js microservices architecture$q$, $q$FxA is split into cooperating services, a content-server for the sign-in UI, an auth-server for account logic, an oauth-server for OAuth 2.0, and a profile-server for shared profile data, all built on Node.js and TypeScript in the mozilla/fxa monorepo.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Client-side key stretching (onepw protocol)$q$, $q$Passwords are run through 1,000 rounds of client-side PBKDF2 plus HKDF before ever reaching the server, and the server applies an additional scrypt-based stretch before storing a verify hash, so raw passwords are never transmitted or stored.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$End-to-end encrypted Sync key derivation$q$, $q$The same key-derivation chain produces scoped encryption keys (kA and kB, later generalized as scoped keys) that let Firefox Sync data be encrypted with keys the server itself cannot reconstruct from stored data alone.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$OAuth 2.0 support for relying parties$q$, $q$The oauth-server component implements OAuth 2.0 so that Mozilla products like Mozilla VPN and Pocket can request scoped, limited access to a user's account without ever handling that user's credentials directly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Self-hostable reference implementation$q$, $q$The full stack can be cloned from GitHub and deployed independently of Mozilla's own servers, letting developers run a private, Firefox-Sync-compatible identity backend, provided they also stand up a matching sync-1.5 storage server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Multi-platform client configuration$q$, $q$Desktop Firefox 52+, iOS 9.0+, and Android (Fennec) 44+ all expose preferences or settings toggles that let a self-hosted FxA instance's auth, content, OAuth, and profile server URLs be substituted for Mozilla's own.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Localized web sign-in experience$q$, $q$The content-server delivers the sign-in and sign-up flow, Terms of Service, and Privacy Policy in the user's preferred locale, reflecting Mozilla's broader multi-language localization program.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Publicly audited security model$q$, $q$Mozilla's security team published a public security audit of Firefox Accounts, and the onepw protocol and API surface are documented openly on the Firefox Ecosystem Platform docs and GitHub wiki for independent review.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Completely free and open source under the permissive-but-copyleft MPL-2.0 license, with no subscription, seat, or usage fees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Cryptographic design (client-side PBKDF2/HKDF stretching plus server-side scrypt) has been publicly documented and independently audited, which is unusual transparency for an identity backend.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Proven at very large scale as the real authentication system behind hundreds of millions of Firefox and Mozilla product installations.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Fully self-hostable, giving privacy-focused teams and browser forks a way to run Firefox-Sync-compatible authentication without depending on Mozilla's own infrastructure.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Not a general-purpose identity platform, it lacks the admin dashboards, enterprise SSO, and broad protocol support of platforms like Auth0, Keycloak, or Ory.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Self-hosting requires running and coordinating multiple Node.js services plus a compatible sync-1.5 storage server just to get full Sync functionality working.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Documentation is written primarily for Mozilla's own internal use case rather than third-party adopters, which raises the learning curve for outside self-hosters.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$No commercial support channel; help for self-hosters is limited to community Matrix chat rather than a dedicated support team.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$What is Firefox Account Server (FxA)?$q$, $q$FxA is Mozilla's open-source, Node.js-based identity and authentication backend that lets users sign in once and use that account across Firefox Sync, Mozilla VPN, Pocket, and other Mozilla products. The public brand was renamed from 'Firefox accounts' to 'Mozilla accounts' in November 2023, but the underlying FxA codebase and accounts.firefox.com URL were kept unchanged.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Is Firefox Account Server free to use?$q$, $q$Yes. FxA is free, open-source software released under the Mozilla Public License 2.0. There is no purchase price or subscription; Mozilla's own hosted instance is free for end users, and self-hosters only pay for their own infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Can I self-host my own Firefox Accounts server?$q$, $q$Yes. Mozilla publishes a 'Run your own Firefox Accounts Server' guide describing how to clone the mozilla/fxa repository and deploy your own auth-server and content-server instances. Because Mozilla's production Sync storage rejects assertions from non-Mozilla FxA instances, a full self-hosted setup also requires running your own compatible sync-1.5 storage server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$How does FxA protect user passwords?$q$, $q$FxA uses a protocol documented as 'onepw.' The Firefox client runs the password through 1,000 rounds of PBKDF2 and then HKDF before sending anything to the server, so the raw password never leaves the device. The server then applies an additional, much heavier scrypt-based stretch before storing a verify hash, meaning even a compromised database still requires expensive computation per password guess.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$When did Firefox Accounts launch?$q$, $q$Firefox Accounts was introduced experimentally in early 2014 and became the default backend for Firefox Sync starting with Firefox 29, replacing Sync's older pairing-code-based setup, in a transition often referred to internally as 'Sync 1.5.'$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$What are the main alternatives to Firefox Account Server?$q$, $q$For general-purpose identity and authentication needs, comparable platforms include Auth0, AWS Cognito, Keycloak, Ory (Kratos and Hydra), Authelia, and SuperTokens. Unlike FxA, most of these are designed as broadly applicable identity platforms for any application, rather than being purpose-built around one browser vendor's Sync and relying-party ecosystem.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Running a private, Firefox-Sync-compatible identity backend$q$, $q$Organizations or privacy-focused individuals who do not want to depend on Mozilla's own servers can self-host the full FxA stack (auth-server, content-server, oauth-server, profile-server) alongside a compatible sync-1.5 storage server to get a working, independent Firefox Sync setup.$q$, $q$Privacy-conscious developers and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Studying a production-grade zero-knowledge-style password protocol$q$, $q$Because the onepw protocol, key-derivation chain, and API surface are fully open and documented, security engineers can study a real, publicly audited implementation of client-side password stretching and scoped key derivation used at browser scale.$q$, $q$Security engineers and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Building or maintaining a Firefox-based browser fork$q$, $q$Teams maintaining Firefox derivatives or forks that want their own branded account and Sync experience can adapt the open-source FxA codebase instead of building an authentication and Sync backend from scratch.$q$, $q$Browser fork maintainers and open-source browser projects$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MPL-2.0 licensed source code on GitHub (mozilla/fxa)","Self-hostable auth-server, content-server, oauth-server, and profile-server","No subscription, seat, or usage fees","Community support via Mozilla's Matrix #fxa room"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Firefox Account Server (FxA) is the open-source identity and authentication backend Mozilla built to power sign-in across Firefox Sync, Mozilla VPN, Pocket, Firefox Add-ons, and other Mozilla relying-party applications. It was rolled out starting around Firefox 29 in 2014 as the replacement for Firefox Sync's older pairing-code system, and the public-facing brand was renamed from 'Firefox accounts' to 'Mozilla accounts' in late 2023, though the accounts.firefox.com URL and underlying FxA codebase were intentionally kept unchanged.$q$, $q$The project lives in the mozilla/fxa monorepo on GitHub and is licensed under the Mozilla Public License 2.0. It is built primarily in TypeScript and JavaScript on Node.js, and is structured as a small set of cooperating microservices: a content-server for the sign-in UI, an auth-server for account and password logic, an oauth-server for OAuth 2.0 flows, and a profile-server for shared profile data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FxA's core technical distinction is its client-side key-stretching protocol (documented as 'onepw'), which combines PBKDF2 and HKDF on the client with a heavier server-side scrypt stretch, so the server never receives or stores a user's raw password and an attacker who steals the account database still faces an expensive scrypt work factor per guess.$q$, $q$The same key-derivation chain produces scoped encryption keys that let Firefox Sync data (bookmarks, history, saved passwords, open tabs) be encrypted end to end with keys the server cannot reconstruct on its own, and it exposes OAuth 2.0 so relying-party apps like Mozilla VPN and Pocket can request limited, scoped access instead of handling credentials directly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$There is no purchase price, subscription, or paid tier for Firefox Account Server itself; it is free, open-source software under the MPL-2.0 license that anyone can clone, audit, and self-host. Mozilla runs its own production instance at no direct cost to end users, and organizations that choose to self-host instead pay only for their own infrastructure (servers, database, and, for full Sync compatibility, a self-hosted sync-1.5 storage server) plus the engineering time to deploy and maintain it.$q$, $q$Because it is infrastructure rather than a commercial product, there are no seat-based plans or feature-gated tiers to compare; the single relevant 'plan' is running the open-source stack yourself or relying on Mozilla's hosted Mozilla accounts service that ships with Firefox.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('864fba7c-ef16-406d-a4f4-ba7e53df55cc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$FireAttention inference engine$q$, $q$A custom CUDA-kernel-based inference engine built in-house that Fireworks says delivers substantially faster token generation than standard open-source serving frameworks, including on large mixture-of-experts models like DeepSeek.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Broad open-model catalog$q$, $q$Hosts more than 100 open-source and proprietary models, including Llama, DeepSeek, Qwen, Mixtral, Kimi, GLM, and Mistral, accessible through a single OpenAI-compatible API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Serverless pay-per-token inference$q$, $q$Metered, postpaid API access with no infrastructure to manage, including discounted pricing for cached input tokens and batch inference jobs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$On-demand dedicated GPU deployments$q$, $q$Reserved H100, H200, B200, and B300 GPU capacity billed per GPU-second for predictable, high-volume production workloads, with no extra charge for start-up time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Managed fine-tuning$q$, $q$Fully managed supervised fine-tuning, direct preference optimization, and reinforcement fine-tuning pipelines priced per million training tokens by model size.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Multi-LoRA model hosting$q$, $q$Deploy and instantly switch between up to 100 fine-tuned model adapters on shared infrastructure at the same price as the base model, useful for per-customer or per-task personalization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Function calling and structured outputs$q$, $q$Native support for function calling, JSON mode, and structured outputs designed for agentic and compound AI applications that chain multiple model and tool calls together.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Enterprise security and compliance$q$, $q$SOC 2 Type II and HIPAA compliance plus ISO 27001, ISO 27701, and ISO 42001 certifications, with private and virtual-private-cloud deployment options for regulated industries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$FireAttention inference engine delivers notably fast, cost-efficient serving compared to stock open-source serving frameworks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Very broad catalog of open-weight models plus support for custom and fine-tuned model uploads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Fine-tuned models and Multi-LoRA adapters are served at the same price as base models, lowering the cost of customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Strong compliance posture (SOC 2 Type II, HIPAA, ISO 27001/27701/42001) suitable for regulated enterprise buyers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Usage-based, per-token and per-GPU-hour pricing across many model sizes and deployment modes can be harder to predict and budget than a flat subscription$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$No proprietary flagship foundation model of its own, so output quality ceiling depends on the open and third-party models it hosts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$On-demand dedicated GPU deployments require infrastructure planning and capacity commitment that smaller teams may find unnecessary for low-volume use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Rapid pricing and product changes driven by fast company growth mean published rates for niche models can shift and should be reverified before large commitments$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$What is Fireworks AI?$q$, $q$Fireworks AI is a generative AI inference and fine-tuning platform that lets developers run open-weight and custom large language models through a fast, OpenAI-compatible API, without managing their own GPU infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Who founded Fireworks AI and when?$q$, $q$Fireworks AI was founded in late 2022 by Lin Qiao, former head of PyTorch at Meta, together with six co-founders who also came from Meta's AI infrastructure and PyTorch teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$How much has Fireworks AI raised, and what is it worth?$q$, $q$Fireworks has raised capital across a Series A, Series B, Series C, and Series D, most recently a $1.5 billion round in July 2026 at a $17.5 billion valuation led by Atreides Management, Index Ventures, and TCV, with NVIDIA and Lightspeed among the participating investors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$How is Fireworks AI priced?$q$, $q$Fireworks uses pay-per-token metered billing for serverless inference, per-GPU-hour billing for dedicated on-demand deployments, and per-million-training-token pricing for fine-tuning, with new accounts receiving a small amount of free credit to get started.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Which models can I run on Fireworks AI?$q$, $q$Fireworks hosts more than 100 open-source and proprietary models, including Llama, DeepSeek, Qwen, Mixtral, Kimi, GLM, and Mistral, and also supports deploying your own custom or fine-tuned models.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$How does Fireworks AI compare to Together AI, Groq, and AWS Bedrock?$q$, $q$Fireworks is generally considered a price-and-performance all-rounder with a broad model catalog and strong fine-tuning support, similar in positioning to Together AI. Groq focuses on raw speed using custom chip hardware but offers fewer models and no fine-tuning, while AWS Bedrock is a hyperscaler-hosted alternative favored by teams already standardized on AWS infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Production LLM application serving$q$, $q$Teams building customer-facing AI products use Fireworks' serverless and on-demand deployments to serve open-weight models at low latency and predictable cost as usage scales.$q$, $q$Product engineering teams at AI-native startups and software companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Per-customer model personalization$q$, $q$Using Multi-LoRA hosting, B2B software companies fine-tune and deploy a distinct model adapter per customer or workflow without paying extra inference cost beyond the base model rate.$q$, $q$B2B SaaS platforms serving multiple enterprise customers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Regulated-industry generative AI$q$, $q$Healthcare, legal, and financial services organizations use Fireworks' HIPAA and SOC 2 Type II compliant infrastructure with private deployment options to run generative AI on sensitive data.$q$, $q$Enterprise teams in healthcare, legal, and financial services$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Serverless Inference$q$, $q$Pay-per-token, from a fraction of a cent per 1M tokens for smaller models$q$, $q$Usage-based, postpaid$q$, NULL, $q$["Access to 100+ open-source and proprietary models","OpenAI-compatible API with function calling and structured outputs","50 percent discount on cached input tokens","50 percent discount on batch inference","$1 in free credits for new accounts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$On-Demand Deployments$q$, $q$$7 per GPU-hour on H100/H200, $10 per GPU-hour on B200, $12 per GPU-hour on B300$q$, $q$Billed per GPU-second$q$, NULL, $q$["Dedicated GPU capacity for predictable high-volume workloads","No extra charge for start-up time","Support for custom and fine-tuned model deployment","Multi-region availability"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Fine-Tuning$q$, $q$From $0.50 to $40 per 1M training tokens depending on model size and method$q$, $q$Pay per training token$q$, NULL, $q$["Supervised fine-tuning (SFT)","Direct preference optimization (DPO)","Reinforcement fine-tuning (RFT)","Multi-LoRA hosting of up to 100 fine-tuned adapters at base-model inference pricing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Dedicated account team and SLAs","Private and virtual-private-cloud deployment options","Volume-based discounts","SOC 2 Type II, HIPAA, and ISO 27001/27701/42001 compliance support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fireworks AI is a generative AI inference platform that gives developers fast, production-grade access to open-weight and custom large language models through a single OpenAI-compatible API. Instead of building its own foundation models, Fireworks focuses on serving models efficiently, hosting more than 100 open-source and proprietary models including Llama, DeepSeek, Qwen, Mixtral, and Mistral.$q$, $q$Founded in late 2022 by Lin Qiao, former head of PyTorch at Meta, and six co-founders also from Meta's AI infrastructure teams, Fireworks has grown from a niche inference API into a broad platform covering serverless inference, dedicated on-demand GPU deployments, batch inference, and managed fine-tuning. The company is headquartered in Redwood City, California, and reported an annualized revenue run rate exceeding $1 billion as of its July 2026 funding round.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core technology is FireAttention, a custom CUDA-kernel inference engine that the company says serves models several times faster than standard open-source serving frameworks, while preserving output quality through targeted quantization.$q$, $q$Beyond raw speed, Fireworks offers managed fine-tuning (supervised fine-tuning, direct preference optimization, and reinforcement fine-tuning), Multi-LoRA hosting for running up to 100 fine-tuned model adapters at base-model pricing, function calling and structured outputs for agentic workflows, and dedicated on-demand GPU deployments for predictable, high-volume production traffic.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fireworks uses metered, pay-per-token billing for serverless inference, with new accounts receiving a small amount of free credit to start. Cached input tokens and batch inference are discounted fifty percent relative to standard rates, and fine-tuned models are served at the same price as their base models.$q$, $q$For predictable, high-volume workloads, Fireworks offers dedicated on-demand GPU deployments billed per GPU-second, at roughly $7 per GPU-hour for H100 and H200 chips, $10 per GPU-hour for B200 chips, and $12 per GPU-hour for B300 chips, with no separate charge for start-up time. Fine-tuning is billed per million training tokens, ranging from about $0.50 for LoRA supervised fine-tuning on smaller models up to $40 for full-parameter DPO on models above 300 billion parameters. Enterprise customers can negotiate custom contracts with volume discounts and private deployment options.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$fine-tuning-and-customization$q$, $q$Fine-Tuning and Model Customization$q$, 2, ARRAY[$q$Fireworks provides fully managed fine-tuning pipelines covering supervised fine-tuning, direct preference optimization, and reinforcement fine-tuning, letting teams adapt open models to their own data without operating their own training infrastructure.$q$, $q$The Multi-LoRA feature lets a customer host and instantly switch between many fine-tuned adapters on shared infrastructure, which is commonly used to personalize a model per customer, tenant, or task in B2B applications without incurring extra inference cost beyond the base model rate.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', $q$security-and-compliance$q$, $q$Security and Compliance$q$, 2, ARRAY[$q$Fireworks has achieved SOC 2 Type II and HIPAA compliance, along with ISO 27001, ISO 27701, and ISO 42001 certifications covering information security, data privacy, and responsible AI management. Data is encrypted in transit and at rest, and the company states it does not retain customer prompt or completion data for open models without explicit opt-in.$q$, $q$These certifications, combined with private and virtual-private-cloud deployment options for enterprise customers, are aimed at regulated industries such as healthcare, financial services, and legal technology that need auditable data-handling guarantees before adopting open-weight model infrastructure.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aff64b96-3f9d-4b60-acba-86586aac9085', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$GPX File Import$q$, $q$Upload a single GPX file or a ZIP archive containing multiple GPX files to automatically create workouts with route, distance, and elevation data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Interactive Map Visualization$q$, $q$Each workout with a GPX trace is displayed on an interactive Leaflet map using OpenStreetMap tiles, showing the exact route taken.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Speed and Elevation Charts$q$, $q$Chart.js-powered graphs show speed and elevation over the course of a workout when the source GPX file includes elevation data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Manual Workout Entry$q$, $q$Workouts can be logged without a GPX file by manually entering the sport type, date, time, duration, and distance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Statistics and Records Dashboard$q$, $q$A monthly calendar view and aggregate statistics dashboard track workout counts, distance, duration, and elevation gain, along with personal records.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Equipment and Weather Tracking$q$, $q$Workouts can be associated with specific equipment (such as running shoes) to track usage, and optional weather-condition data can be attached automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Multi-User and REST API$q$, $q$Supports multiple user accounts with administrative moderation tools, plus a documented REST API with OAuth 2.0 authentication for third-party integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$ActivityPub Federation$q$, $q$Newer versions support following other users, commenting on workouts, and a federated activity feed built on the ActivityPub protocol, connecting separate FitTrackee instances.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Completely free and open source with no paid tier, subscription, or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$All workout and location data stays on infrastructure the user controls, addressing privacy concerns with commercial fitness platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$AGPL-3.0 license ensures that even hosted or modified versions must remain source-available$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Actively maintained with a long release history, translated into more than a dozen languages via Weblate$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Requires self-hosting knowledge: Docker, PostgreSQL/PostGIS, and general server maintenance are needed to run it$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$No official managed or hosted plan, so there is no zero-setup option for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$The project explicitly describes itself as under heavy development, with some newer features potentially unstable$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Single-maintainer-driven development means feature velocity and support responsiveness can be slower than commercial competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Is FitTrackee free to use?$q$, $q$Yes. FitTrackee is free and open-source software licensed under AGPL-3.0. There is no subscription fee; the only cost is the server infrastructure needed to self-host it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Do I need to self-host FitTrackee?$q$, $q$FitTrackee does not offer an official managed cloud version, so it must be deployed on your own server, VPS, or NAS, typically using Docker and Docker Compose alongside a PostgreSQL/PostGIS database.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$What file formats does FitTrackee support?$q$, $q$FitTrackee primarily imports GPX files, including ZIP archives containing multiple GPX files. Workouts can also be entered manually without a file.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Is FitTrackee a good Strava alternative?$q$, $q$FitTrackee is widely cited in self-hosting communities as one of the closest open-source replacements for Strava, offering route maps, statistics, equipment tracking, and social features like following and commenting, though its interface is simpler and it lacks Strava's built-in device ecosystem.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$What technology stack does FitTrackee use?$q$, $q$The backend is built with Python and Flask, using PostgreSQL with the PostGIS extension for geospatial data. The frontend is a Vue 3 and TypeScript single-page application using Leaflet for maps and Chart.js for charts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Who develops FitTrackee?$q$, $q$FitTrackee is developed primarily by a maintainer known as SamR1, with the canonical repository hosted on Codeberg and mirrored to GitHub. The underlying repository dates back to 2017, and the project has had over 140 releases.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Privacy-focused activity logging$q$, $q$Athletes who don't want their GPS routes and workout history stored on a commercial platform can log runs, rides, and hikes on a server they fully control.$q$, $q$Privacy-conscious runners and cyclists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Self-hosting stack integration$q$, $q$Home-lab and self-hosting enthusiasts who already run services like media servers or password managers can add FitTrackee to track fitness data alongside their other self-managed applications.$q$, $q$Self-hosting and FOSS community members$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Small federated fitness communities$q$, $q$Groups of friends or club members can run a shared FitTrackee instance, follow each other's workouts, and comment via the ActivityPub-based social feed without relying on a corporate social network.$q$, $q$Running clubs and small fitness communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$Open Source$q$, $q$Free$q$, $q$N/A - self-hosted$q$, NULL, $q$["Unlimited workouts and users on your own server","GPX import, map visualization, and statistics","Multi-user support with admin tools","REST API with OAuth 2.0","ActivityPub federation and social features","Full AGPL-3.0 source code access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FitTrackee is a free, open-source web application for tracking outdoor workouts such as running, cycling, and hiking, designed from the ground up to be self-hosted rather than delivered as a commercial cloud service. Users upload GPX files exported from GPS watches, phones, or bike computers, and FitTrackee renders the route on an interactive map, calculates distance, elevation, and pace statistics, and stores everything in a database the user controls.$q$, $q$The project is maintained primarily by a developer known publicly as SamR1, with its canonical source repository hosted on Codeberg and mirrored to GitHub for CI and package distribution. It is licensed under the GNU Affero General Public License v3 (AGPL-3.0), a copyleft license chosen specifically to preserve user freedoms even when the software is run as a network service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality centers on workout creation from GPX files or ZIP archives of multiple GPX files, with support for manual workout entry when no GPS trace exists. Each workout can display an interactive Leaflet/OpenStreetMap-powered map alongside Chart.js-rendered speed and elevation graphs when elevation data is present in the file.$q$, $q$Beyond basic tracking, FitTrackee includes a calendar dashboard of workouts and personal records, an aggregate statistics view across custom date ranges, equipment tracking (for example, logging shoe mileage), optional weather-condition tagging, multi-user support with administrative moderation tools, a documented REST API with OAuth 2.0, and lightweight social features including following, commenting, and an ActivityPub-based federated feed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FitTrackee is entirely free and open source under the AGPL-3.0 license; there is no paid tier, subscription, or managed hosting offering from the project itself. The only cost is the infrastructure the user provides, typically a small VPS, home server, or NAS running Docker and PostgreSQL with the PostGIS extension.$q$, $q$Because AGPL-3.0 requires that anyone offering a modified version as a network service also publish that modified source code, third parties can legally run and even resell hosted FitTrackee instances, but any such offering must remain source-available under the same license, preserving the openness of the underlying project.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2325b7f-fda2-40f8-adc4-5f3940ce498f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$700+ Managed Connectors$q$, $q$Pre-built, fully maintained connectors for SaaS applications, databases, event streams, files and enterprise systems, eliminating the need to build and maintain custom integration scripts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Automated Schema Drift Handling$q$, $q$Detects and automatically propagates source schema changes (new, removed or renamed columns) into the destination warehouse without manual pipeline updates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Log-Based Change Data Capture$q$, $q$Enterprise-grade, low-latency database replication technology, originally acquired via HVR Software in 2021, for high-volume on-premises and cloud database sources.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Teleport Sync$q$, $q$A code-free, log-free database replication method (from the 2021 Teleport Data acquisition) that combines snapshot simplicity with near log-based performance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$dbt Core and SQLMesh Transformations$q$, $q$Native integration with dbt Core plus Fivetran's own Fivetran Transformations, extended after the 2025 Tobiko Data acquisition with SQLMesh-based transformation tooling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Fivetran Activations (Reverse ETL)$q$, $q$Syncs governed, transformed warehouse data back into operational business applications such as CRMs and marketing platforms, built on the acquired Census platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Flexible Sync Frequency$q$, $q$Sync intervals ranging from one minute on higher tiers to fifteen minutes or longer on Standard, configurable per connector.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Enterprise Security and Compliance$q$, $q$SOC 2, HIPAA and GDPR support across plans, with customer-managed encryption keys, PCI DSS Level 1 certification and private networking available on Business Critical.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Very large library of over 700 fully managed connectors reduces engineering time spent building and maintaining pipelines$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Automatic schema drift handling and reliable incremental syncing lower ongoing maintenance burden compared to hand-built or open-source pipelines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Strong enterprise security and compliance options (SOC 2, HIPAA, GDPR, PCI DSS Level 1, customer-managed keys, private networking) on higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Expanding platform scope after the Census, Tobiko Data and dbt Labs deals now covers movement, transformation and activation from a single vendor$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Monthly Active Rows pricing can become expensive and less predictable for high-volume or high-churn tables compared to flat-rate competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Deletes now count toward paid MAR usage, which can increase costs for workloads with frequent record deletion$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Less flexibility for building fully custom or self-hosted connectors compared to open-source alternatives like Airbyte or Meltano$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Fastest one-minute sync frequency and several enterprise controls are reserved for higher-priced Enterprise and Business Critical tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$What is Fivetran used for?$q$, $q$Fivetran is used to automatically extract data from SaaS applications, databases and other sources and load it into a cloud data warehouse or lakehouse like Snowflake, BigQuery, Redshift or Databricks, so analytics and data teams have a continuously synced, centralized dataset for reporting, BI and AI workloads without building custom pipelines.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$How does Fivetran's pricing work?$q$, $q$Fivetran uses a usage-based pricing model built around Monthly Active Rows (MAR), the number of unique rows inserted, updated or deleted by a connector each month. A Free plan covers up to 500,000 MAR; paid Standard, Enterprise and Business Critical plans apply a small base fee per connection plus tiered MAR consumption pricing that decreases at higher volumes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$What data warehouses does Fivetran support as destinations?$q$, $q$Fivetran supports major cloud data warehouses and lakehouses including Snowflake, Google BigQuery, Amazon Redshift, Databricks, Azure Synapse Analytics and PostgreSQL, among other managed destinations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Did Fivetran acquire HVR?$q$, $q$Yes. Fivetran announced its agreement to acquire HVR Software, a log-based change data capture vendor, in September 2021 for approximately 700 million dollars, and the deal closed in October 2021, adding enterprise-grade replication technology for large and complex database sources.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Did Fivetran merge with dbt Labs?$q$, $q$Yes. Fivetran signed a definitive all-stock merger agreement with dbt Labs, the company behind the open-source dbt Core transformation framework, on October 13, 2025. The merger closed on June 1, 2026, with Fivetran CEO George Fraser leading the combined company, which serves more than 100,000 data teams and was approaching 600 million dollars in annual recurring revenue at close.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Does Fivetran offer a free plan?$q$, $q$Yes. Fivetran's Free plan includes 500,000 Monthly Active Rows per month for connections, 3,500 MAR for activations and 5,000 monthly model runs for transformations, with no credit card required to start.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Centralizing SaaS and database data for BI and analytics$q$, $q$Teams connect sources like Salesforce, HubSpot, PostgreSQL and MySQL to Fivetran, which continuously syncs the data into a cloud warehouse so analysts can build dashboards and reports on a single, reliable dataset without maintaining custom ETL scripts.$q$, $q$Data engineers and analytics engineers at mid-market and enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Enterprise database replication and migration$q$, $q$Organizations with large, complex on-premises or cloud database estates use Fivetran's log-based change data capture (originally from the HVR acquisition) and Teleport Sync to replicate high-volume transactional data into a warehouse with minimal latency and no source database performance impact.$q$, $q$Enterprise IT and data platform teams managing large-scale database environments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Reverse ETL and operational analytics activation$q$, $q$After transforming and modeling data in the warehouse, teams use Fivetran Activations to sync governed segments and metrics back into operational tools such as CRMs, ad platforms and marketing automation systems, closing the loop between analytics and business action.$q$, $q$RevOps, marketing operations and growth teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Free$q$, $q$$0$q$, $q$Free, no credit card required$q$, NULL, $q$["500,000 Monthly Active Rows (MAR) per month for connections","3,500 MAR per month for activations","5,000 monthly model runs for transformations","Access to the connector catalog to evaluate the platform"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Standard$q$, $q$Usage-based (small base charge per connection plus tiered MAR pricing)$q$, $q$Monthly pay-as-you-go or annual contract (annual offers savings)$q$, NULL, $q$["700+ fully managed connectors","200+ managed activation destinations","Unlimited users","15-minute sync frequency","dbt Core integration","Role-based access control","REST API access","SSH tunnels"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Enterprise$q$, $q$Usage-based (higher tiered MAR rate than Standard)$q$, $q$Monthly pay-as-you-go or annual contract$q$, NULL, $q$["All Standard features","1-minute sync frequency","Fivetran Activations Audience Hub","Enterprise database connectors","Custom roles","VPN tunnels (annual contracts only)","Multi-cloud provider selection (AWS, GCP, Azure)","Hybrid deployment capability"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$Business Critical$q$, $q$Usage-based, with a higher base commitment (from around $5,000/month)$q$, $q$Annual contract$q$, NULL, $q$["All Enterprise features","Customer-managed encryption keys","PCI DSS Level 1 certification","Private networking options","99.99% uptime SLA","Regional failover","SOC 2, HIPAA and GDPR compliance support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fivetran is a fully managed ELT (extract-load-transform) platform founded in 2012 by George Fraser and Taylor Brown out of Y Combinator's Winter 2013 batch. It automates the extraction and loading of data from more than 700 SaaS applications, databases, event streams and files into cloud data warehouses and lakehouses such as Snowflake, BigQuery, Redshift, Databricks and Azure Synapse.$q$, $q$Instead of requiring engineers to hand-build and maintain fragile integration scripts, Fivetran ships pre-built connectors that handle authentication, incremental syncing, automatic schema creation and schema drift detection out of the box. The company is headquartered in Oakland, California, with additional offices including Denver, Toronto, Dublin, London, Amsterdam, Munich, Novi Sad, Bengaluru and Sydney.$q$, $q$Fivetran reached unicorn status with a 1.2 billion dollar valuation in 2020, then raised a 565 million dollar Series D in September 2021 at a 5.6 billion dollar valuation, the same month it announced the acquisition of change-data-capture vendor HVR Software for approximately 700 million dollars. In 2025 and 2026 Fivetran expanded further, acquiring reverse ETL platform Census and transformation company Tobiko Data, and completing an all-stock merger with dbt Labs on June 1, 2026, to form a combined data movement and transformation company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Fivetran offers a catalog of over 700 fully managed connectors for common SaaS tools (Salesforce, HubSpot, Zendesk, NetSuite), databases (PostgreSQL, MySQL, SQL Server, Oracle, MongoDB) and enterprise systems (SAP, Workday), each maintained by Fivetran's engineering team rather than the customer.$q$, $q$Automatic schema drift handling means that when a source system adds, removes or renames a field, Fivetran propagates that change into the destination warehouse without manual intervention, a key differentiator from self-built or lightly maintained open-source pipelines.$q$, $q$Sync frequency scales from one-minute updates on Enterprise and Business Critical plans down to fifteen-minute or longer syncs on Standard, and enterprise database replication benefits from log-based change data capture technology brought in through the HVR acquisition alongside Fivetran's own Teleport Sync method.$q$, $q$On the transformation and activation side, Fivetran integrates natively with dbt Core, offers its own Fivetran Transformations and, since the Tobiko Data acquisition, SQLMesh-based transformation tooling, while Fivetran Activations (built on the acquired Census platform) enables reverse ETL syncs of governed warehouse data back into operational business applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fivetran prices primarily by Monthly Active Rows (MAR), a usage-based metric counting the unique rows inserted, updated or deleted by a connector each month, rather than charging flat per-connector or per-seat fees. A Free plan includes 500,000 MAR per month for connections, 3,500 MAR for activations and 5,000 monthly model runs for transformations, with no credit card required.$q$, $q$Paid tiers, Standard, Enterprise and Business Critical, apply a small base charge per active connection plus tiered MAR consumption pricing that decreases at higher volumes. Standard includes unlimited users, fifteen-minute syncs, dbt Core integration and REST API access; Enterprise adds one-minute syncs, custom roles, VPN tunnels and multi-cloud or hybrid deployment; and Business Critical adds customer-managed encryption keys, PCI DSS Level 1 certification, private networking and a 99.99 percent uptime SLA for regulated workloads.$q$, $q$Because pricing scales with row volume rather than connector count, costs can rise quickly for high-churn tables with frequent inserts, updates or deletes, which is a common point of comparison against flat-rate competitors like Stitch.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
