INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Feature flags and toggles$q$, $q$Wrap any piece of functionality in a flag and turn it on or off instantly for all users, specific segments, or a percentage rollout, without redeploying code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Remote configuration$q$, $q$Attach string, numeric, or JSON payload values to flags so application copy, limits, or behavior can be changed remotely in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$A/B and multivariate testing$q$, $q$Run controlled experiments by serving different flag variations to different user cohorts and measuring the impact on key metrics, available from the Start-Up plan up.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$User segments and identities$q$, $q$Target flags at unlimited user segments and individual identities based on custom traits, enabling precise rollout targeting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Self-hosting via Docker and Kubernetes$q$, $q$Deploy the entire open-source platform on your own infrastructure using an official Docker Compose file or Kubernetes Helm charts for full data control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Broad SDK coverage$q$, $q$Official client and server-side SDKs for more than a dozen languages and frameworks including JavaScript, React, Next.js, Python, Java, .NET, Ruby, Go, Swift, and Kotlin.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Enterprise governance$q$, $q$Roles, permissions, change requests, and audit logs on the Scale-Up and Enterprise plans give larger teams control and traceability over flag changes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$SSO and 2FA authentication$q$, $q$Two-factor authentication is available from the Start-Up plan, with SAML/SSO and LDAP/SCIM support added on Scale-Up and Enterprise tiers respectively.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Genuinely open-source core with the flexibility to self-host on your own infrastructure at no license cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Generous free tier with unlimited flags, environments, and segments, not just a limited trial$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Deployment flexibility across hosted SaaS, private cloud, and self-hosted options in one product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Transparent, comparatively affordable pricing versus enterprise-focused competitors like LaunchDarkly$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$No built-in product analytics or session replay, unlike all-in-one platforms such as PostHog$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Lacks advanced statistical experimentation engines found in dedicated experimentation platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Free plan is limited to a single team member, so collaboration requires an immediate upgrade$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Self-hosting requires DevOps effort to maintain Docker or Kubernetes infrastructure and upgrades$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Is Flagsmith free to use?$q$, $q$Yes. Flagsmith has a free hosted plan that includes up to 50,000 requests per month, one team member, and unlimited feature flags, environments, and segments. Since the core platform is also open source, teams can self-host it entirely for free, subject to their own infrastructure costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Can Flagsmith be self-hosted?$q$, $q$Yes. Flagsmith's core is open source under a BSD-3-Clause license (with some components under MIT), and it provides an official Docker Compose configuration as well as Kubernetes Helm charts for self-hosting on private infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Was Flagsmith previously called Bullet Train?$q$, $q$Yes. The product originated as an internal tool called Bullet Train, built by co-founder Kyle Johnson at a London product engineering agency. The company rebranded to Flagsmith for clearer positioning and better organic search visibility; the legal entity Bullet Train Ltd remains the company behind the product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Does Flagsmith support A/B testing?$q$, $q$Yes. A/B and multivariate testing is available starting on the Start-Up paid plan, letting teams serve different flag variations to user cohorts and measure their impact.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$How does Flagsmith compare to LaunchDarkly?$q$, $q$LaunchDarkly is a closed-source, enterprise-focused platform known for advanced targeting and governance at higher price points. Flagsmith offers similar core flagging and governance capabilities at a lower price, with the added option of a fully open-source, self-hostable deployment that LaunchDarkly does not offer.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Has Flagsmith raised venture capital funding?$q$, $q$No. Flagsmith is a bootstrapped company. The founders have publicly stated they chose not to raise a traditional Series A, relying instead on a small amount of angel investment (estimated at roughly $130,000 to $230,000 by data providers) and company revenue to fund growth.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Progressive feature rollouts$q$, $q$Engineering teams gate new functionality behind a flag and roll it out gradually to a percentage of users or specific segments, reducing the risk of production incidents from big-bang releases.$q$, $q$Software engineering teams at SaaS and product companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$A/B testing new functionality$q$, $q$Product teams run controlled experiments by serving different flag variations to different user cohorts and measuring the effect on conversion, engagement, or revenue metrics.$q$, $q$Product managers and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Compliance-driven self-hosted deployments$q$, $q$Regulated organizations such as financial services, healthcare, or government contractors deploy Flagsmith entirely within their own infrastructure via Docker or Kubernetes to keep flag and user data inside their network perimeter.$q$, $q$Enterprises and regulated industries with data residency requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 50,000 requests/month","1 team member","Unlimited feature flags, environments, identities, and segments","API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Start-Up$q$, $q$$40/month (yearly) or $45/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["Up to 1,000,000 requests/month","3 team members","Unlimited projects","Scheduled flags","Two-factor authentication","A/B and multivariate testing","3rd party integrations","Email technical support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Scale-Up$q$, $q$$250/month (yearly) or $300/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["5,000,000+ requests/month","5 team members included (up to 20 at $50/member/month)","SAML/SSO authentication","Roles, permissions, change requests, and audit logs","Priority email and chat support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["5,000,000+ requests/month","20+ team members","Tailored hosting: Cloud, Private Cloud, or Self-Hosted","LDAP and SCIM support","Onboarding and training","Enterprise SLA with priority real-time support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Flagsmith is an open-source feature flagging, remote configuration, and A/B testing platform that helps engineering teams decouple deployment from release. Instead of shipping new code and hoping it works, teams wrap functionality in a flag and control who sees it, in real time, from a central dashboard.$q$, $q$Founded in London in 2018 by Ben Rometsch and Kyle Johnson, Flagsmith grew out of an internal tool called Bullet Train that the pair built while running a product engineering agency. The product was later rebranded to Flagsmith for clearer positioning and better search visibility, and the company has remained bootstrapped ever since, reaching roughly $1.5 million in annual recurring revenue without a venture-backed Series A.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core capability is feature flag management: unlimited flags, environments, identities, and user segments are available even on the free tier, letting teams gate functionality by user, cohort, or percentage rollout without a code deploy.$q$, $q$Flagsmith also supports remote configuration (attaching string, numeric, or JSON values to flags to change app behavior on the fly), native A/B and multivariate testing on paid plans, scheduled flags, and enterprise governance tooling such as role-based permissions, change requests, audit logs, and SAML/SSO.$q$, $q$A defining feature is deployment flexibility: Flagsmith is available as fully managed SaaS, private cloud, or self-hosted via Docker Compose or Kubernetes/Helm, which lets regulated or privacy-sensitive teams run the entire platform inside their own infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Flagsmith uses a freemium model. The Free plan covers up to 50,000 requests per month for a single user with unlimited flags and environments. The Start-Up plan starts at $40/month (billed yearly) for up to 1,000,000 requests, three team members, A/B testing, and 2FA.$q$, $q$The Scale-Up plan is $250/month (billed yearly) for 5,000,000-plus requests, SSO, and governance features like audit logs and change requests, with additional seats at $50/member/month. An Enterprise plan offers custom pricing for tailored hosting, LDAP/SCIM, and an SLA. Because the core is open source, teams can also self-host for free, subject to their own infrastructure costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
