INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('019204fd-182f-40f5-9827-49ed1e395308', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Tag-based discussions$q$, $q$Threads are organized using flexible tags instead of rigid nested subforums, allowing forums to be structured by topic and cross-referenced more freely.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Single-page application frontend$q$, $q$Built with Mithril.js, the interface loads once and updates dynamically as members browse discussions, reply, and navigate without full page reloads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Composer-based extension system$q$, $q$Core functionality and add-ons are installed and updated as Composer packages, with a documented Extension API for building custom PHP and JavaScript extensions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Groups and permissions$q$, $q$Role-based access control lets administrators grant or restrict abilities such as posting, moderating, or viewing specific tags at a granular level.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Markdown and WYSIWYG editor$q$, $q$Members can write posts using lightweight Markdown formatting or a rich What-You-See-Is-What-You-Get editing mode, depending on installed extensions and preference.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Notifications and email digests$q$, $q$In-browser notifications, mentions, subscriptions, and optional email digest extensions keep members informed of new activity relevant to them.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Theming and customization$q$, $q$Administrators can adjust forum-wide styling, install community or premium themes, and apply custom CSS through the admin dashboard without touching core code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$REST API$q$, $q$A documented REST API exposes forum data and actions, enabling integrations, custom clients, and headless or embedded use cases beyond the default frontend.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Core software is fully free and MIT-licensed with no feature paywalls, unlike commercial platforms such as vBulletin or XenForo.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Single-page application frontend built on Mithril.js feels noticeably faster and lighter than traditional full-page-reload forum software like classic phpBB.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Composer-based extension architecture and documented Extension API make it straightforward for developers to build and share custom functionality.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Actively governed by the nonprofit Flarum Foundation, giving the project institutional continuity independent of any single maintainer.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Requires self-hosting knowledge, including PHP, Composer, and a MySQL or MariaDB database, since Flarum offers no official managed hosting of its own.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$The project took an unusually long time to reach a stable 1.0 release, moving through roughly sixteen beta versions across nearly six years of public testing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Some of the most advanced functionality is only available through premium, paid third-party extensions rather than being built into core.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$The newest 2.x branch requires a relatively recent PHP 8.3 or higher runtime, which can require a server upgrade for site owners on older shared hosting plans.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Is Flarum free to use?$q$, $q$Yes. Flarum's core software is free and open source under the MIT license, and it can be downloaded, self-hosted, and modified at no cost. Some advanced functionality is available only through optional paid premium extensions sold by independent developers on Flarum's marketplace.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Does Flarum offer its own hosted or cloud version?$q$, $q$No. Flarum does not operate an official paid hosting service; an early plan to pair a hosted offering with its 2014 Kickstarter campaign was dropped in favor of pure open-source distribution. Site owners who do not want to self-host can use independent third-party managed-hosting providers such as Elestio, 20i, TMDHosting, or 365i.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$What technology does Flarum use?$q$, $q$Flarum's backend is written in PHP using components from the Laravel framework, and its frontend is a single-page application built with the Mithril.js JavaScript framework. Extensions and themes are distributed and installed as Composer packages.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Who created Flarum and when?$q$, $q$Toby Zerner conceived Flarum's design philosophy around 2010 and built early prototypes by 2012. The project was publicly open-sourced in December 2014 after Zerner canceled a Kickstarter campaign, and Franz Liedke, creator of the earlier FluxBB forum software, joined the effort in March 2015. Flarum reached its first stable 1.0.0 release on May 27, 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$How does Flarum compare to Discourse and phpBB?$q$, $q$Compared to Discourse, Flarum is generally lighter to self-host and does not push users toward a paid hosted plan. Compared to phpBB, Flarum offers a more modern single-page interface instead of full-page reloads. Both Discourse and phpBB have larger, longer-established extension and plugin ecosystems in certain areas.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Who governs the Flarum project today?$q$, $q$Flarum is led by Daniel Klabbers and is legally owned by the Flarum Foundation, a nonprofit entity (registered in the Netherlands as Stichting Flarum) established after original creator Toby Zerner stepped back from the project in July 2019 to pursue a separate premium forum software venture.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Customer support and peer-to-peer help communities$q$, $q$Companies use Flarum to run self-service support forums where customers can ask questions, share solutions, and reduce direct support ticket volume, as demonstrated by mobile network giffgaff's large peer-support community.$q$, $q$Support and customer success teams at product and telecom companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Niche hobby and interest communities$q$, $q$Flarum's lightweight footprint and free MIT license make it accessible for independent site owners and hobbyists building topic-focused discussion communities without ongoing licensing costs.$q$, $q$Independent community builders and hobbyist site owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Developer and open-source project forums$q$, $q$Open-source and developer-tool projects use Flarum's REST API and extension system to run community discussion boards that can be customized and integrated with existing developer workflows.$q$, $q$Open-source maintainers and developer relations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core forum software under the MIT license","Unlimited discussions, tags, and members","Composer-based installation and updates","Access to hundreds of free community extensions and themes","Requires own server, PHP, Composer, and MySQL or MariaDB database"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Premium Extensions Marketplace$q$, $q$Varies by extension (set by independent developers)$q$, $q$One-off purchase or subscription, depending on the extension$q$, NULL, $q$["Advanced extensions built by vetted, invited third-party developers","Sold directly through Flarum's official marketplace","Installable and updatable across any number of connected forums","Optional add-on layer on top of the always-free core software"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$Third-Party Managed Hosting$q$, $q$Varies by provider (for example, from roughly $11 to $15 per month)$q$, $q$Monthly$q$, NULL, $q$["Offered by independent providers such as Elestio, 20i, TMDHosting, and 365i, not by Flarum itself","Typically includes installation, automated backups, SSL, and updates","No official affiliation with or revenue share to the Flarum project"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Flarum is a free, open-source discussion forum platform built with a PHP and Laravel-based backend and a Mithril.js single-page application frontend, released under the MIT license. It is designed to be installed on a site owner's own server using Composer, PHP's package manager, and is aimed at communities that want a fast, modern forum without the overhead of older, page-reload-based forum software.$q$, $q$The project traces back to a design philosophy Toby Zerner conceived around 2010 and prototyped by 2012, and it is commonly described as growing out of the lineage of two earlier PHP forum projects, FluxBB and esoTalk, reflecting the backgrounds of Zerner and FluxBB creator Franz Liedke, who both worked on the project in its early years. Flarum was open-sourced publicly in December 2014 after an initial Kickstarter campaign was canceled in favor of free distribution, and it reached its first stable 1.0.0 release on May 27, 2021, after an unusually long multi-year public beta period. Since 2019, the project has been led by Daniel Klabbers and is now legally owned by the nonprofit Flarum Foundation, registered in the Netherlands.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Flarum provides discussions organized by tags rather than traditional nested subforums, role-based groups and permissions, a Markdown and WYSIWYG-capable post editor, and real-time-feeling navigation powered by its single-page frontend. Notifications, mentions, and subscriptions are handled through bundled first-party extensions rather than being hardwired into the core, which keeps the base installation lean.$q$, $q$Almost every additional capability, such as social login, private messaging, advanced moderation and audit logging, search improvements, SEO tooling, and integrations with external services, is added through Flarum's Composer-based extension system, which exposes a documented Extension API for PHP and JavaScript developers. Hundreds of free community extensions are available on GitHub and Packagist, alongside an official premium extensions marketplace where invited developers sell more advanced add-ons directly to forum owners.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$technical-architecture$q$, $q$Technical Architecture$q$, 2, ARRAY[$q$Flarum's backend is a PHP application that uses components from the Laravel framework and exposes a REST API that the frontend, and any external client, communicates with. The frontend was originally written in Ember.js when Flarum launched in 2015 but was later rewritten in Mithril.js, a smaller JavaScript framework, to keep the single-page interface lightweight.$q$, $q$Self-hosting Flarum requires a PHP-capable web server, a MySQL or MariaDB-compatible database, and Composer for installing the core and any extensions. The actively developed 2.x branch requires PHP 8.3 or newer as of 2026, while the long-lived 1.x branch, culminating in the 1.8.x series, remains compatible with PHP 7.3 and above and is still widely deployed on production forums that have not yet upgraded.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Flarum itself does not sell an official hosted or cloud product; an early plan to pair a paid hosting offering with the project's 2014 Kickstarter campaign was dropped within weeks in favor of pure open-source distribution. The core software remains free to download, self-host, and modify indefinitely, with no feature limits in the free tier.$q$, $q$Site owners who prefer not to manage their own infrastructure can use independent, third-party managed-hosting providers such as Elestio, 20i, TMDHosting, and 365i, which charge their own monthly fees for installation, updates, backups, and support. The only spending that flows directly into the Flarum ecosystem is optional: forum owners can purchase individual premium extensions, priced by their independent developers as one-off purchases or subscriptions, through Flarum's own marketplace.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdf350cb-3f1d-4f22-b2fc-e83f597e6faf', $q$comparison$q$, $q$How Flarum Compares$q$, 2, ARRAY[$q$Flarum's closest competitors are Discourse, phpBB, vBulletin, XenForo, and NodeBB. Discourse, built on Ruby on Rails, offers a similarly modern experience but is generally heavier to self-host and is most often consumed as a paid hosted service. phpBB is an older, more traditional PHP forum package with a full-page-reload interface and a large legacy extension library. vBulletin and XenForo are long-standing commercial, closed-source forum platforms sold under paid software licenses rather than distributed as open source. NodeBB takes a comparable single-page-application approach but is built on Node.js and MongoDB instead of PHP and MySQL.$q$, $q$Flarum differentiates itself through a fully free, MIT-licensed core, a lighter and faster interface than phpBB or Discourse tend to deliver on comparable hardware, and a minimalist, extension-first design philosophy that keeps the base installation small so site owners only add the complexity their community genuinely needs.$q$]::text[], 4);
